-- ============================================================================
-- AutoElite Motors — Seed Data
-- ============================================================================
-- This file populates a fresh database with the SAME content as the live demo:
--   • 15 cars (with images, specs, prices in KES)
--   • 3 blog posts
--   • 6 customer testimonials
--   • 8 services
--   • 4 team members
--   • Site settings (branding, contact, hours)
--   • Chatbot knowledge base
--   • Default admin user (username: admin, password: admin123)
--
-- USAGE:
--   psql "$DATABASE_URL" -f scripts/seed.sql
--
-- Or paste the entire contents into Neon/Supabase SQL editor and click Run.
--
-- This script is IDEMPOTENT — safe to re-run; it wipes & repopulates content
-- tables. It does NOT touch customer data (bookings, inquiries, etc.).
-- ============================================================================

BEGIN;

-- Clear existing content (preserves customer/transactional tables)
TRUNCATE TABLE
  cars, blog_posts, testimonials, services, team_members,
  site_settings, chatbot_knowledge, admin_users
RESTART IDENTITY CASCADE;

-- ============================================================================
-- Content data (dumped from live database)
-- ============================================================================


-- Data for Name: blog_posts; Type: TABLE DATA; Schema: public; Owner: -

INSERT INTO public.blog_posts VALUES (1, 'top-luxury-suvs-2023', 'Top 5 Luxury SUVs of 2023: The Ultimate Guide', 'The luxury SUV market has never been more competitive. We break down the top contenders and help you decide which one is right for you.', 'The luxury SUV segment has evolved dramatically over the past decade. Today''s premium SUVs offer performance, technology, and comfort that would have seemed impossible just a few years ago. In this comprehensive guide, we examine the five best luxury SUVs available in 2023, from the supremely capable Range Rover Sport to the technologically brilliant Mercedes GLE.

Whether you prioritize performance, interior luxury, off-road capability, or cutting-edge technology, there is a perfect luxury SUV for every discerning buyer. Our expert team has driven and evaluated each of these vehicles extensively to bring you the most comprehensive and honest assessment available.', 'buying-guides', 'https://images.unsplash.com/photo-1609521263047-f8f205293f24?w=800', true, '2023-11-01 00:00:00', '2026-04-12 11:09:50.931834');
INSERT INTO public.blog_posts VALUES (2, 'financing-your-dream-car', 'How to Finance Your Dream Car: A Complete Guide', 'Understanding your financing options is key to making a smart car purchase. Our finance experts break down everything you need to know.', 'Buying a premium vehicle is one of the most significant financial decisions you will make. Understanding your financing options can save you thousands of dollars and ensure you get the most favourable terms available.

In this guide, our finance team walks you through everything: from understanding interest rates and loan terms to the benefits of different financing structures. We also explain the difference between financing and leasing, and when each option might be the better choice for your situation.', 'financing-tips', 'https://images.unsplash.com/photo-1565043589221-1a6fd9ae45c7?w=800', true, '2023-10-15 00:00:00', '2026-04-12 11:09:50.931834');
INSERT INTO public.blog_posts VALUES (3, 'new-arrivals-november-2023', 'November 2023 New Arrivals: Exceptional Additions to Our Inventory', 'This month we welcome some truly spectacular vehicles to our showroom. From a barely-used Range Rover Sport to the stunning Audi RS6 Avant.', 'November has brought us some of the finest vehicles we have had the pleasure of welcoming into our inventory. Each month, we carefully select only the best examples of premium vehicles to offer our discerning clients.

This month standout addition is undoubtedly the 2022 Audi RS6 Avant in Nardo Grey with just 9,000 miles on the clock. With the full Carbon Black exterior package and Bang & Olufsen 3D sound system, this is arguably the finest RS6 Avant we have ever stocked.', 'latest-arrivals', 'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=800', true, '2023-11-10 00:00:00', '2026-04-12 11:09:50.931834');


