INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (1, '2023-mercedes-benz-gle-350', 'Mercedes-Benz GLE 350', 'Mercedes-Benz', 'GLE', '350', 2023, 89500.00, NULL, 12000, '2.0L Turbo', 'Automatic', 'Petrol', 'AWD', 'SUV', 5, 4, 'Obsidian Black', 'AE-2023-001', NULL, 'new', 'available', 'Stunning luxury SUV in pristine condition with full service history', 'Experience the pinnacle of luxury SUV driving with this immaculate 2023 Mercedes-Benz GLE 350. Wrapped in Obsidian Black with a Macchiato Beige interior, this vehicle combines breathtaking style with cutting-edge technology and supreme comfort.', '["Panoramic Sunroof", "Burmester Sound System", "Heated Seats", "Wireless Charging", "360 Camera", "Active Parking Assist", "Air Suspension"]', '["Active Brake Assist", "Blind Spot Assist", "Lane Keeping Assist", "Adaptive Cruise Control", "Traffic Sign Recognition"]', '["MBUX Infotainment", "Apple CarPlay", "Heated & Ventilated Seats", "Dual Zone Climate", "Electric Tailgate"]', '["12.3 inch Display", "MBUX Voice Control", "Wireless CarPlay", "Heads Up Display", "Digital Instrument Cluster"]', '["https://images.unsplash.com/photo-1609521263047-f8f205293f24?w=800", "https://images.unsplash.com/photo-1618843479313-40f8afb4b4d8?w=800", "https://images.unsplash.com/photo-1555215695-3004980ad54e?w=800", "https://images.unsplash.com/photo-1563720223185-11003d516935?w=800"]', NULL, true, true, true, 'Los Angeles, CA', 'Luxury', '2026-04-12 11:09:50.906473', '2026-04-12 11:09:50.906473', false, NULL, NULL, 'in_stock', NULL, NULL, 0, NULL, NULL);
INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (2, '2022-bmw-x5-m50i', 'BMW X5 M50i', 'BMW', 'X5', 'M50i', 2022, 95000.00, NULL, 18500, '4.4L V8 Twin Turbo', 'Automatic', 'Petrol', 'xDrive AWD', 'SUV', 5, 4, 'Mineral White', 'AE-2022-002', NULL, 'used', 'available', 'High-performance luxury SUV with M Sport package, low mileage', 'This remarkable BMW X5 M50i represents the perfect fusion of performance and luxury. With its 523hp twin-turbocharged V8 engine, this SUV delivers supercar-level performance while maintaining the versatility and comfort expected of a premium family vehicle.', '["M Sport Package", "BMW Individual", "Laser Headlights", "Panoramic Sky Lounge", "Bowers & Wilkins Sound", "Active Steering"]', '["Automatic Emergency Braking", "Pedestrian Detection", "Rear Collision Warning", "Lane Departure Warning", "Head-Up Display"]', '["Massage Seats", "4-Zone Climate", "Ambient Lighting", "Wireless Charging", "Executive Package"]', '["BMW Live Cockpit Pro", "5G Ready", "Amazon Alexa Integration", "Gesture Control", "Wireless CarPlay"]', '["https://images.unsplash.com/photo-1555215695-3004980ad54e?w=800", "https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=800", "https://images.unsplash.com/photo-1617531653332-bd46c16f4d5f?w=800"]', NULL, true, true, true, 'Beverly Hills, CA', 'Luxury', '2026-04-12 11:09:50.906473', '2026-04-12 11:09:50.906473', false, NULL, NULL, 'in_stock', NULL, NULL, 0, NULL, NULL);
INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (3, '2021-porsche-cayenne-s', 'Porsche Cayenne S', 'Porsche', 'Cayenne', 'S', 2021, 78000.00, NULL, 24000, '2.9L V6 Biturbo', 'Automatic', 'Petrol', 'AWD', 'SUV', 5, 4, 'Carrara White', 'AE-2021-003', NULL, 'used', 'available', 'Iconic Porsche SUV with Sport Chrono and PASM suspension', 'The Porsche Cayenne S offers an unmatched combination of sports car performance and SUV versatility. This stunning Carrara White example comes loaded with the Sport Chrono Package, PASM Sport suspension, and premium Bose surround sound.', '["Sport Chrono Package", "PASM Sport Suspension", "21-inch RS Spyder Wheels", "Porsche InnoDrive", "Panoramic Roof"]', '["Porsche Active Safety", "Lane Change Assist", "Night Vision Assist", "Surround View Camera"]', '["14-Way Power Seats", "Heated Rear Seats", "4-Zone Climate", "Ventilated Front Seats"]', '["PCM with Navigation", "Bose Surround Sound", "Apple CarPlay", "Android Auto"]', '["https://images.unsplash.com/photo-1544636331-e26879cd4d9b?w=800", "https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=800", "https://images.unsplash.com/photo-1609521263047-f8f205293f24?w=800"]', NULL, true, true, true, 'Santa Monica, CA', 'Luxury', '2026-04-12 11:09:50.906473', '2026-04-12 11:09:50.906473', false, NULL, NULL, 'in_stock', NULL, NULL, 0, NULL, NULL);
INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (4, '2023-range-rover-sport-hse', 'Range Rover Sport HSE', 'Land Rover', 'Range Rover Sport', 'HSE', 2023, 105000.00, NULL, 5500, '3.0L I6 Mild Hybrid', 'Automatic', 'Hybrid', 'AWD', 'SUV', 5, 4, 'Santorini Black', 'AE-2023-004', NULL, 'new', 'available', 'Nearly new Range Rover Sport with full warranty and every option', 'The all-new Range Rover Sport HSE represents the ultimate blend of capability and sophistication. This nearly-new example features every available option and still carries full manufacturer warranty.', '["Dynamic Air Suspension", "Meridian Signature Sound", "Sliding Panoramic Roof", "22-inch Alloys", "Matrix LED Headlights"]', '["Emergency Braking", "Blind Spot Monitor", "Clear Exit Monitor", "Wade Sensing", "Terrain Response 2"]', '["SVO Ambient Lighting", "Heated Steering Wheel", "Massage Front Seats", "Cabin Air Purification"]', '["Pivi Pro 11.4-inch Touchscreen", "Digital Rear View Mirror", "Activity Key", "Over-The-Air Updates"]', '["https://images.unsplash.com/photo-1614162692292-7ac56d7f7f1e?w=800", "https://images.unsplash.com/photo-1609521263047-f8f205293f24?w=800", "https://images.unsplash.com/photo-1549399542-7e3f8b79c341?w=800"]', NULL, true, true, true, 'Malibu, CA', 'Luxury', '2026-04-12 11:09:50.906473', '2026-04-12 11:09:50.906473', false, NULL, NULL, 'in_stock', NULL, NULL, 0, NULL, NULL);
