INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (12, '2020-nissan-x-trail-20xi', '2020 Nissan X-Trail 20Xi', 'Nissan', 'X-Trail', '20Xi', 2020, 28500.00, NULL, 31000, '2.0L Petrol', 'CVT', 'Petrol', '4WD', 'SUV', 7, 5, 'Graphite Blue', NULL, NULL, 'used', 'available', 'Grade 4 Nissan X-Trail 7-seater from Japan with ProPilot assist.', 'The 2020 Nissan X-Trail 20Xi features ProPilot semi-autonomous driving. Perfect 7-seater family SUV for Nairobi roads.', NULL, '["ProPilot Assist", "ABS", "Airbags (6)", "Emergency Brake", "Blind Spot Warning"]', '["ProPilot", "Navigation", "Around View Monitor", "Power Seats", "Dual Zone Climate", "Apple CarPlay"]', NULL, '["https://images.unsplash.com/photo-1559416523-140ddc3d238c?w=1200", "https://images.unsplash.com/photo-1568772585407-9361f9bf3a87?w=1200"]', NULL, false, true, true, 'Nairobi, Kenya', NULL, '2026-04-12 12:25:47.381012', '2026-04-12 12:25:47.381012', true, '4', 'NT32-987654', 'arrived', '2024-10-01', '2024-11-10', 0, NULL, NULL);
INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (13, '2021-mazda-cx5-25s-awd', '2021 Mazda CX-5 25S AWD', 'Mazda', 'CX-5', '25S AWD', 2021, 31000.00, NULL, 22000, '2.5L SKYACTIV-G', 'Automatic', 'Petrol', 'AWD', 'SUV', 5, 5, 'Soul Red Crystal', NULL, NULL, 'used', 'available', 'Grade 5 Mazda CX-5 in stunning Soul Red Crystal. Near-perfect condition.', 'Grade 5 Mazda CX-5 25S with Bose audio, heads-up display. The iconic Soul Red Crystal paint is a Mazda exclusive.', NULL, '["i-Activsense", "Lane Keep Assist", "Radar Cruise Control", "AEB"]', '["Bose 12-Speaker", "Heads-Up Display", "Wireless Charging", "Heated Seats", "Sunroof"]', NULL, '["https://images.unsplash.com/photo-1552519507-da3b142c6e3d?w=1200", "https://images.unsplash.com/photo-1494976388531-d1058494cdd8?w=1200"]', NULL, true, true, true, 'Nairobi, Kenya', NULL, '2026-04-12 12:25:47.381012', '2026-04-12 12:25:47.381012', true, '5', 'KF2P-456789', 'arrived', '2024-11-05', '2024-12-18', 0, NULL, NULL);
INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (14, '2018-honda-stepwgn-spada', '2018 Honda Stepwgn Spada', 'Honda', 'Stepwgn', 'Spada', 2018, 24000.00, NULL, 55000, '1.5L Turbo', 'CVT', 'Petrol', 'FWD', 'Van', 8, 5, 'Premium White Pearl', NULL, NULL, 'used', 'available', 'Honda Stepwgn Spada 8-seater minivan from Japan. Currently clearing at Mombasa Port.', 'Japan best-selling family minivan with magic sliding doors. Currently clearing customs at Mombasa — available in ~2 weeks.', NULL, '["Honda Sensing", "AEB", "Lane Watch Camera", "Airbags (6)"]', '["Magic Sliding Doors", "Panoramic Sunroof", "Navigation", "3-Row Seating"]', NULL, '["https://images.unsplash.com/photo-1553440569-bcc63803a83d?w=1200"]', NULL, false, true, true, 'Mombasa Port (Clearing)', NULL, '2026-04-12 12:25:47.381012', '2026-04-12 12:25:47.381012', true, '4', 'RP3-0089123', 'clearing', '2025-01-10', NULL, 0, NULL, NULL);
INSERT INTO public.cars (id, slug, title, make, model, trim, year, price, discounted_price, mileage, engine_size, transmission, fuel_type, drivetrain, body_type, seats, doors, color, stock_number, vin, condition, availability, short_description, description, features, safety_features, comfort_features, tech_features, gallery, video_url, is_featured, is_published, financing_available, location, category, created_at, updated_at, is_japanese_import, auction_grade, chassis_number, shipping_status, japan_departure_date, kenya_arrival_date, view_count, price_floor, cost_price) VALUES (15, '2022-toyota-harrier-z', '2022 Toyota Harrier Z', 'Toyota', 'Harrier', 'Z Leather Package', 2022, 45000.00, NULL, 15000, '2.0L Dynamic Force', 'CVT', 'Petrol', 'FWD', 'SUV', 5, 5, 'Emotional Red', NULL, NULL, 'used', 'in_transit', 'Grade 5 Toyota Harrier Z in rare Emotional Red. Arriving April 2025.', 'The 4th generation Toyota Harrier Z in exclusive Emotional Red. Grade 5 with panoramic glass roof, JBL audio, digital rear mirror.', NULL, '["Toyota Safety Sense 2.0", "Pre-Collision System", "Radar Cruise", "Lane Tracing Assist"]', '["Panoramic Glass Roof", "Digital Rear Mirror", "JBL 9-Speaker", "Wireless CarPlay", "Heated Seats"]', NULL, '["https://images.unsplash.com/photo-1617469767786-9164a0f97d14?w=1200", "https://images.unsplash.com/photo-1580414057403-c5f451f30e1c?w=1200"]', NULL, true, true, true, 'In Transit — ETA April 2025', NULL, '2026-04-12 12:25:47.381012', '2026-04-12 12:25:47.381012', true, '5', 'MXUA80-0045123', 'in_transit', '2025-02-20', '2025-04-05', 0, NULL, NULL);


-- Data for Name: chatbot_knowledge; Type: TABLE DATA; Schema: public; Owner: -

INSERT INTO public.chatbot_knowledge VALUES (1, 'I want to talk to owner', 'Habari! Karibu. To speak with the **owner/management** at **AutoElite Motors**, please use either of these:

- **Call / WhatsApp:** **+254 700 234 567**
- **Email:** **sales@autoelitemotors.co.ke**

If you prefer, you can also visit us at **Ngong Road, Nairobi (next to Prestige Plaza)** during **Mon–Sat 8AM–6PM | Sun 10AM–4PM**.

Share your **name** and what it’s about (buying, selling, complaint, partnership), and I’ll guide you on the fastest way to get you connected.', '["talk","owner"]', 'openai', 0, '2026-04-18 14:23:42.638594', '2026-04-18 14:23:42.638594');
INSERT INTO public.chatbot_knowledge VALUES (2, 'My name is John', 'Habari John, karibu sana.

To get you connected to the **owner/management**, please send this message on **WhatsApp: +254 700 234 567** (or call the same number):

**Template to copy-paste:**
- *Hi AutoElite, my name is John. I’d like to speak with the owner/management regarding [brief reason]. What’s the best time to reach them? My number is [your phone].*

Tell me what it’s about (e.g., **car inquiry, financing, complaint, partnership**) and I’ll help you phrase it vizuri.', '["name","john"]', 'openai', 0, '2026-04-18 14:24:05.49265', '2026-04-18 14:24:05.49265');


-- Data for Name: services; Type: TABLE DATA; Schema: public; Owner: -

INSERT INTO public.services VALUES (1, 'Premium Car Sales', 'We offer an exclusive selection of verified premium vehicles from the world''s leading manufacturers. Every car in our inventory undergoes a rigorous inspection process.', 'Car', true, 1, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (2, 'Vehicle Sourcing', 'Can''t find your dream car in our current inventory? Our global network allows us to source specific makes, models, and configurations to your exact requirements.', 'Search', true, 2, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (3, 'Financing Support', 'We offer flexible financing options through our network of trusted financial partners. Competitive rates, straightforward terms, and quick approvals.', 'CreditCard', true, 3, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (4, 'Trade-In Service', 'Get a fair, transparent valuation for your current vehicle and apply it directly to your next purchase. We accept all makes and models.', 'ArrowLeftRight', true, 4, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (5, 'Vehicle Inspection', 'Every vehicle is subjected to a comprehensive 200-point inspection before entering our inventory. We provide full inspection reports on request.', 'ClipboardCheck', true, 5, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (6, 'Documentation Support', 'Our experienced team handles all paperwork including title transfers, registration, and any import documentation required.', 'FileText', true, 6, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (7, 'After-Sale Guidance', 'Our relationship with clients does not end at the sale. We provide ongoing support, service recommendations, and guidance for all post-purchase needs.', 'HeartHandshake', true, 7, '2026-04-12 11:09:50.926308');
INSERT INTO public.services VALUES (8, 'Import Assistance', 'We specialize in sourcing and importing premium vehicles from international markets. Full customs clearance and compliance management included.', 'Globe', true, 8, '2026-04-12 11:09:50.926308');


-- Data for Name: site_settings; Type: TABLE DATA; Schema: public; Owner: -

INSERT INTO public.site_settings VALUES (1, 'Elite Motors', 'Kenya''s Premier Luxury Car Dealership', '+254 734336227', '254734336227', 'sales@autoelitemotors.co.ke', 'Ngong Road, next to Prestige Plaza', 'Nairobi', 'https://maps.google.com/?q=4820+Automotive+Boulevard+Los+Angeles+CA', 'https://facebook.com/autoelitemotors', 'https://instagram.com/autoelitemotors', 'https://twitter.com/autoelitemotors', 'https://youtube.com/@autoelitemotors', 'Mon-Sat: 8:00AM - 7:00PM  |  Sunday: 10:00AM - 5:00PM', 'Drive the Extraordinary', 'Premium vehicles sourced from Japan and beyond — delivered in Nairobi', 'About AutoElite Motors', 'For over 15 years, AutoElite Motors has been Los Angeles''s most trusted premium car dealership. We specialize in luxury, performance, and premium vehicles, offering an unparalleled buying experience with full transparency, competitive pricing, and exceptional after-sale support. Our passionate team of automotive experts is dedicated to matching every customer with their perfect vehicle.', 'https://images.unsplash.com/photo-1562141961-9e5cf8f9c0f0?w=800', 12, 80, 2400, '2026-04-12 14:41:04.501', 'Kenya', '', '', 'KES', 130, NULL, NULL, NULL, NULL, NULL, NULL, 'Nairobi''s home for premium Japanese imports & luxury cars', 'true', NULL, 'AutoElite Motors — Premium car dealership in Nairobi, Kenya. Japanese imports, luxury vehicles, KRA import assistance.', '', NULL, '#DC2626', '{"SUV":"","Luxury":"","Sports":"","Sedan":""}', 'true');


-- Data for Name: team_members; Type: TABLE DATA; Schema: public; Owner: -

INSERT INTO public.team_members VALUES (1, 'Michael Sterling', 'Founder & Principal Dealer', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=400', 'Luxury & Exotic Vehicles', '+1 (555) 234-5678', '+15552345678', 'michael@autoelitemotors.com', 'With over 20 years in the premium automotive industry, Michael founded AutoElite Motors with a vision to redefine the car buying experience in Los Angeles. His passion for extraordinary vehicles and commitment to customer satisfaction are the cornerstones of our success.', 1, '2026-04-12 11:09:50.921157');
INSERT INTO public.team_members VALUES (2, 'Alexandra Brooks', 'Senior Sales Consultant', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=400', 'European Luxury Brands', '+1 (555) 234-5679', '+15552345679', 'alexandra@autoelitemotors.com', 'Alexandra brings 12 years of luxury automotive experience, specializing in European marques including Mercedes-Benz, BMW, Audi, and Porsche. Her encyclopedic knowledge of these vehicles ensures every client finds their perfect match.', 2, '2026-04-12 11:09:50.921157');
INSERT INTO public.team_members VALUES (3, 'James Park', 'Finance Manager', 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=400', 'Vehicle Financing & Leasing', '+1 (555) 234-5680', '+15552345680', 'james@autoelitemotors.com', 'James has helped thousands of clients secure the best possible financing terms for their dream vehicles. With relationships across major financial institutions, he consistently delivers competitive rates and flexible terms.', 3, '2026-04-12 11:09:50.921157');
INSERT INTO public.team_members VALUES (4, 'Sofia Martinez', 'Client Relations Manager', 'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=400', 'After-Sale Support & Trade-Ins', '+1 (555) 234-5681', '+15552345681', 'sofia@autoelitemotors.com', 'Sofia ensures that every client who leaves our showroom becomes a lifelong partner. From trade-in valuations to post-purchase support, she is dedicated to creating an exceptional experience that extends well beyond the sale.', 4, '2026-04-12 11:09:50.921157');


-- Data for Name: testimonials; Type: TABLE DATA; Schema: public; Owner: -

INSERT INTO public.testimonials VALUES (1, 'James Richardson', 'Beverly Hills, CA', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=200', 5, 'Absolutely incredible experience. The team at AutoElite went above and beyond to find me the perfect Mercedes GLE. Professional, transparent, and genuinely passionate about cars. I will never buy from anywhere else.', 'Mercedes-Benz GLE 350', true, '2026-04-12 11:09:50.914688');
INSERT INTO public.testimonials VALUES (2, 'Sarah Mitchell', 'Malibu, CA', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=200', 5, 'From the moment I walked in, I felt like a valued customer. No pressure tactics, just genuine expertise and honest advice. My Range Rover Sport is everything I dreamed of. The financing process was smooth and fair.', 'Range Rover Sport HSE', true, '2026-04-12 11:09:50.914688');
INSERT INTO public.testimonials VALUES (3, 'Marcus Johnson', 'Santa Monica, CA', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=200', 5, 'I was skeptical about buying a used car, but AutoElite completely changed my perspective. Full vehicle history, independent inspection, and a 3-month warranty included. My BMW X5 is in flawless condition.', 'BMW X5 M50i', true, '2026-04-12 11:09:50.914688');
INSERT INTO public.testimonials VALUES (4, 'Elena Rodriguez', 'Los Angeles, CA', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=200', 5, 'The trade-in process was incredibly fair and transparent. They gave me top dollar for my old car and made the upgrade to the Porsche Cayenne seamlessly easy. Exceptional service from start to finish.', 'Porsche Cayenne S', true, '2026-04-12 11:09:50.914688');
INSERT INTO public.testimonials VALUES (5, 'David Thompson', 'Pasadena, CA', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=200', 5, 'AutoElite sourced my dream Audi RS6 Avant within 2 weeks from their network. Exactly the spec I wanted, at a fair price, with full documentation. This is how car buying should always work.', 'Audi RS6 Avant', true, '2026-04-12 11:09:50.914688');
INSERT INTO public.testimonials VALUES (6, 'Amanda Chen', 'Studio City, CA', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=200', 5, 'My husband and I both bought our cars from AutoElite within the same month. The family discount was a wonderful touch, but honestly the transparency and professionalism is why we keep coming back.', 'Toyota Alphard Executive Lounge', true, '2026-04-12 11:09:50.914688');


